
import marshal
import base64
import zlib
import hashlib
import sys
import os

# Embedded password (encoded in base64)
PASSWORD = "KEAmSXBXaVBLRUdGY2cydERNQjYjU2FWV093bUxmak4="
ENCRYPTED_DATA = b''

class Crypto:
    @staticmethod
    def get_password():
        # Decode password from base64
        return base64.b64decode(PASSWORD).decode()
    
    @staticmethod
    def derive_key(password):
        salt = b'salt_1234567890'
        key = password.encode() + salt
        for _ in range(10):
            key = hashlib.sha256(key).digest()
        return key
    
    @staticmethod
    def xor_decrypt(data, key):
        if isinstance(data, str):
            data = data.encode()
        key_bytes = key * (len(data) // len(key) + 1)
        key_bytes = key_bytes[:len(data)]
        return bytes([a ^ b for a, b in zip(data, key_bytes)])

def decrypt_code(encrypted_data, password):
    try:
        # Reverse Layer 7: Base64 decode
        layer7 = base64.b64decode(encrypted_data)
        
        # Reverse Layer 6: Unmarshal
        layer6 = marshal.loads(layer7)
        
        # Reverse Layer 5: XOR decryption
        key = Crypto.derive_key(password)
        layer5 = Crypto.xor_decrypt(layer6, key)
        
        # Reverse Layer 4: Base64 decode
        layer4 = base64.b64decode(layer5)
        
        # Reverse Layer 3: Unmarshal
        layer3 = marshal.loads(layer4)
        
        # Reverse Layer 2: Decompress
        layer2 = zlib.decompress(layer3).decode()
        
        # Reverse Layer 1: Reverse string
        original = layer2[::-1]
        
        return original
        
    except Exception as e:
        print(f"Decryption failed: {e}")
        sys.exit(1)

def main():
    # Get password from embedded data
    password = Crypto.get_password()
    
    # Decrypt
    decrypted_code = decrypt_code(ENCRYPTED_DATA, password)
    
    # Execute
    exec(decrypted_code, {'__name__': '__main__'})

if __name__ == "__main__":
    main()
